import React, { useEffect, useState } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import { Buffer } from 'buffer';
import * as SecureStore from 'expo-secure-store';
import * as Crypto from 'expo-crypto';

const generateSecureToken = async () => {
  const randomBytes = await Crypto.getRandomBytesAsync(32);
  return Buffer.from(randomBytes).toString('hex');
};

const App = () => {
  const [token, setToken] = useState('');

  const handleGenerateToken = async () => {
    const newToken = await generateSecureToken();
    setToken(newToken);
    await SecureStore.setItemAsync('sessionToken', newToken);
    Alert.alert('Token Generated', `Your session token is: ${newToken}`);
  };

  useEffect(() => {
    const fetchToken = async () => {
      const storedToken = await SecureStore.getItemAsync('sessionToken');
      if (storedToken) {
        setToken(storedToken);
      }
    };
    fetchToken();
  }, []);

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Text>Session Token: {token}</Text>
      <Button title="Generate Token" onPress={handleGenerateToken} />
    </View>
  );
};

export default App;